import{_ as t,c as a,o as e,a1 as i}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"Использование: запрос квот ИИ | opencode-mystatus","description":"Узнайте два способа запроса квот ИИ: слэш-команда /mystatus и вопросы на естественном языке. Плагин opencode-mystatus быстро показывает использование квот OpenAI, Zhipu AI, Z.ai, GitHub Copilot и Google Cloud.","frontmatter":{"title":"Использование: запрос квот ИИ | opencode-mystatus","sidebarTitle":"Использование","subtitle":"Использование: запрос квот ИИ","description":"Узнайте два способа запроса квот ИИ: слэш-команда /mystatus и вопросы на естественном языке. Плагин opencode-mystatus быстро показывает использование квот OpenAI, Zhipu AI, Z.ai, GitHub Copilot и Google Cloud.","tags":["Быстрый старт","Слэш-команда","Естественный язык"],"prerequisite":["start-quick-start"],"order":2},"headers":[],"relativePath":"ru/vbgate/opencode-mystatus/start/using-mystatus/index.md","filePath":"ru/vbgate/opencode-mystatus/start/using-mystatus/index.md"}'),n={name:"ru/vbgate/opencode-mystatus/start/using-mystatus/index.md"};function o(l,s,p,d,r,h){return e(),a("div",null,[...s[0]||(s[0]=[i(`<h1 id="использование-mystatus-слэш-команды-и-естественныи-язык" tabindex="-1">Использование mystatus: слэш-команды и естественный язык <a class="header-anchor" href="#использование-mystatus-слэш-команды-и-естественныи-язык" aria-label="Permalink to &quot;Использование mystatus: слэш-команды и естественный язык&quot;">​</a></h1><h2 id="чему-вы-научитесь" tabindex="-1">Чему вы научитесь <a class="header-anchor" href="#чему-вы-научитесь" aria-label="Permalink to &quot;Чему вы научитесь&quot;">​</a></h2><ul><li>Использовать слэш-команду <code>/mystatus</code> для единого запроса квот всех ИИ-платформ</li><li>Задавать вопросы на естественном языке, чтобы OpenCode автоматически вызывал инструмент mystatus</li><li>Понимать различия между двумя способами вызова и сценарии применения</li></ul><h2 id="ваша-текущая-проблема" tabindex="-1">Ваша текущая проблема <a class="header-anchor" href="#ваша-текущая-проблема" aria-label="Permalink to &quot;Ваша текущая проблема&quot;">​</a></h2><p>Вы используете несколько ИИ-платформ для разработки (OpenAI, Zhipu AI, GitHub Copilot и др.), хотите знать, сколько осталось квот на каждой платформе, но не хотите входить на каждую платформу по отдельности — это слишком неудобно.</p><h2 id="когда-использовать-этот-метод" tabindex="-1">Когда использовать этот метод <a class="header-anchor" href="#когда-использовать-этот-метод" aria-label="Permalink to &quot;Когда использовать этот метод&quot;">​</a></h2><ul><li><strong>При необходимости быстрого просмотра квот всех платформ</strong>: проверка перед ежедневной разработкой для рационального планирования использования</li><li><strong>При необходимости узнать конкретную квоту платформы</strong>: например, хотите подтвердить, скоро ли закончится OpenAI</li><li><strong>При необходимости проверить работоспособность конфигурации</strong>: только что настроили новый аккаунт, нужно проверить, можно ли нормально запросить</li></ul><div class="info custom-block"><p class="custom-block-title">Предварительная проверка</p><p>В этом руководстве предполагается, что вы уже <a href="/docs/opencodedocs/ru/vbgate/opencode-mystatus/start/quick-start/">установили плагин opencode-mystatus</a>. Если не установили, пожалуйста, сначала выполните шаги установки.</p></div><h2 id="основная-идея" tabindex="-1">Основная идея <a class="header-anchor" href="#основная-идея" aria-label="Permalink to &quot;Основная идея&quot;">​</a></h2><p>opencode-mystatus предлагает два способа вызова инструмента mystatus:</p><ol><li><strong>Слэш-команда <code>/mystatus</code></strong>: быстрый, прямой, однозначный, подходит для частых запросов</li><li><strong>Вопросы на естественном языке</strong>: более гибкий, подходит для запросов в конкретных сценариях</li></ol><p>Оба способа вызывают один и тот же инструмент <code>mystatus</code>, инструмент параллельно запрашивает квоты всех настроенных ИИ-платформ, возвращает результат с индикатором прогресса, статистикой использования и обратным отсчётом.</p><h2 id="пошаговое-выполнение" tabindex="-1">Пошаговое выполнение <a class="header-anchor" href="#пошаговое-выполнение" aria-label="Permalink to &quot;Пошаговое выполнение&quot;">​</a></h2><h3 id="шаг-1-используите-слэш-команду-для-запроса-квот" tabindex="-1">Шаг 1: Используйте слэш-команду для запроса квот <a class="header-anchor" href="#шаг-1-используите-слэш-команду-для-запроса-квот" aria-label="Permalink to &quot;Шаг 1: Используйте слэш-команду для запроса квот&quot;">​</a></h3><p>В OpenCode введите следующую команду:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/mystatus</span></span></code></pre></div><p><strong>Почему</strong> Слэш-команда — это механизм быстрых команд OpenCode, можно быстро вызвать предопределённый инструмент. Команда <code>/mystatus</code> напрямую вызывает инструмент mystatus, дополнительных параметров не требуется.</p><p><strong>Вы должны увидеть</strong>: OpenCode вернёт информацию о квотах всех настроенных платформ, формат следующий:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## OpenAI 账号额度</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Account:        user@example.com (team)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3小时限额</span></span>
<span class="line"><span>█████████████████████████ 剩余 85%</span></span>
<span class="line"><span>重置: 2h 30m后</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 智谱 AI 账号额度</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Account:        9c89****AQVM (Coding Plan)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5小时 token 限额</span></span>
<span class="line"><span>█████████████████████████ 剩余 95%</span></span>
<span class="line"><span>已用: 0.5M / 10.0M</span></span>
<span class="line"><span>重置: 4h后</span></span></code></pre></div><p>Каждая платформа отобразит:</p><ul><li>Информация об аккаунте (email или замаскированный API Key)</li><li>Индикатор прогресса (визуальное отображение остатка)</li><li>Обратный отсчёт до сброса</li><li>Использованное и общее количество (часть платформ)</li></ul><h3 id="шаг-2-задаите-вопрос-на-естественном-языке" tabindex="-1">Шаг 2: Задайте вопрос на естественном языке <a class="header-anchor" href="#шаг-2-задаите-вопрос-на-естественном-языке" aria-label="Permalink to &quot;Шаг 2: Задайте вопрос на естественном языке&quot;">​</a></h3><p>Кроме слэш-команды, вы можете задать вопрос на естественном языке, OpenCode автоматически распознает намерение и вызовет инструмент mystatus.</p><p>Попробуйте эти способы задать вопрос:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Check</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> OpenAI</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> quota</span></span></code></pre></div><p>или</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">How</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> much</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Codex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> quota</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> do</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> I</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> have</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> left?</span></span></code></pre></div><p>или</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Show</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AI</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> account</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre></div><p><strong>Почему</strong> Запросы на естественном языке более соответствуют обычным диалогам, подходят для постановки вопросов в конкретных сценариях разработки. OpenCode распознает, что вы хотите запросить квоту, через семантическое сопоставление и автоматически вызовет инструмент mystatus.</p><p><strong>Вы должны увидеть</strong>: Результат вывода такой же, как у слэш-команды, отличается только способ вызова.</p><h3 id="шаг-3-понимание-настроики-слэш-команды" tabindex="-1">Шаг 3: Понимание настройки слэш-команды <a class="header-anchor" href="#шаг-3-понимание-настроики-слэш-команды" aria-label="Permalink to &quot;Шаг 3: Понимание настройки слэш-команды&quot;">​</a></h3><p>Как работает слэш-команда <code>/mystatus</code>? Она определена в файле конфигурации OpenCode.</p><p>Откройте <code>~/.config/opencode/opencode.json</code>, найдите часть <code>command</code>:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;plugin&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;opencode-mystatus&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;mystatus&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;description&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Query quota usage for all AI accounts&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;template&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Use the mystatus tool to query quota usage. Return the result as-is without modification.&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>Описание ключевых параметров</strong>:</p><table tabindex="0"><thead><tr><th>Параметр</th><th>Значение</th><th>Назначение</th></tr></thead><tbody><tr><td><code>description</code></td><td>&quot;Query quota usage for all AI accounts&quot;</td><td>Описание в списке команд</td></tr><tr><td><code>template</code></td><td>&quot;Use to mystatus tool...&quot;</td><td>Указывает OpenCode, как обрабатывать эту команду</td></tr></tbody></table><p><strong>Зачем нужен template</strong> template — это &quot;инструкция&quot; для OpenCode, указывающая: когда пользователь вводит <code>/mystatus</code>, вызвать инструмент mystatus и вернуть результат как есть (без изменений).</p><h2 id="контрольная-точка-✅" tabindex="-1">Контрольная точка ✅ <a class="header-anchor" href="#контрольная-точка-✅" aria-label="Permalink to &quot;Контрольная точка ✅&quot;">​</a></h2><p>Убедитесь, что вы освоили два способа использования:</p><table tabindex="0"><thead><tr><th>Навык</th><th>Метод проверки</th><th>Ожидаемый результат</th></tr></thead><tbody><tr><td>Слэш-команда запрос</td><td>Введите <code>/mystatus</code></td><td>Отображается информация о квотах всех платформ</td></tr><tr><td>Запрос на естественном языке</td><td>Введите &quot;Check my OpenAI quota&quot;</td><td>Отображается информация о квотах</td></tr><tr><td>Понимание настройки</td><td>Проверьте opencode.json</td><td>Найдена конфигурация команды mystatus</td></tr></tbody></table><h2 id="предупреждения-о-типичных-ошибках" tabindex="-1">Предупреждения о типичных ошибках <a class="header-anchor" href="#предупреждения-о-типичных-ошибках" aria-label="Permalink to &quot;Предупреждения о типичных ошибках&quot;">​</a></h2><h3 id="частая-ошибка-1-слэш-команда-не-отвечает" tabindex="-1">Частая ошибка 1: Слэш-команда не отвечает <a class="header-anchor" href="#частая-ошибка-1-слэш-команда-не-отвечает" aria-label="Permalink to &quot;Частая ошибка 1: Слэш-команда не отвечает&quot;">​</a></h3><p><strong>Проявление</strong>: после ввода <code>/mystatus</code> никакой реакции</p><p><strong>Причина</strong>: файл конфигурации OpenCode неправильно настроен слэш-команду</p><p><strong>Решение</strong>:</p><ol><li>Откройте <code>~/.config/opencode/opencode.json</code></li><li>Убедитесь, что часть <code>command</code> содержит конфигурацию <code>mystatus</code> (см. шаг 3)</li><li>Перезапустите OpenCode</li></ol><h3 id="частая-ошибка-2-вопрос-на-естественном-языке-не-вызывает-инструмент-mystatus" tabindex="-1">Частая ошибка 2: Вопрос на естественном языке не вызывает инструмент mystatus <a class="header-anchor" href="#частая-ошибка-2-вопрос-на-естественном-языке-не-вызывает-инструмент-mystatus" aria-label="Permalink to &quot;Частая ошибка 2: Вопрос на естественном языке не вызывает инструмент mystatus&quot;">​</a></h3><p><strong>Проявление</strong>: после ввода &quot;Check my OpenAI quota&quot; OpenCode не вызывает инструмент mystatus, а пытается ответить сам</p><p><strong>Причина</strong>: OpenCode неправильно распознал ваше намерение</p><p><strong>Решение</strong>:</p><ol><li>Попробуйте более чёткое выражение: &quot;Use mystatus tool to check my OpenAI quota&quot;</li><li>Или используйте слэш-команду <code>/mystatus</code>, это более надёжно</li></ol><h3 id="частая-ошибка-3-отображение-未找到任何已配置的账号" tabindex="-1">Частая ошибка 3: Отображение &quot;未找到任何已配置的账号&quot; <a class="header-anchor" href="#частая-ошибка-3-отображение-未找到任何已配置的账号" aria-label="Permalink to &quot;Частая ошибка 3: Отображение &quot;未找到任何已配置的账号&quot;&quot;">​</a></h3><p><strong>Проявление</strong>: после выполнения <code>/mystatus</code> отображается &quot;未找到任何已配置的账号&quot;</p><p><strong>Причина</strong>: ещё не настроены данные аутентификации ни одной платформы</p><p><strong>Решение</strong>:</p><ul><li>Настройте данные аутентификации минимум одной платформы (OpenAI, Zhipu AI, Z.ai, GitHub Copilot или Google Cloud)</li><li>Подробности см. в описании настройки в руководстве <a href="/docs/opencodedocs/ru/vbgate/opencode-mystatus/start/quick-start/">Быстрый старт</a></li></ul><h2 id="итог-урока" tabindex="-1">Итог урока <a class="header-anchor" href="#итог-урока" aria-label="Permalink to &quot;Итог урока&quot;">​</a></h2><p>Инструмент mystatus предлагает два способа использования:</p><ol><li><strong>Слэш-команда <code>/mystatus</code></strong>: быстрый и прямой, подходит для частых запросов</li><li><strong>Вопросы на естественном языке</strong>: более гибкий, подходит для конкретных сценариев</li></ol><p>Оба способа параллельно запрашивают квоты всех настроенных ИИ-платформ, возвращают результат с индикатором прогресса и обратным отсчётом. Настройка слэш-команды определена в <code>~/.config/opencode/opencode.json</code>, через template указывается, как OpenCode вызывает инструмент mystatus.</p><h2 id="следующии-урок" tabindex="-1">Следующий урок <a class="header-anchor" href="#следующии-урок" aria-label="Permalink to &quot;Следующий урок&quot;">​</a></h2><blockquote><p>В следующем уроке мы изучим <strong><a href="/docs/opencodedocs/ru/vbgate/opencode-mystatus/start/understanding-output/">Понимание вывода: индикатор прогресса, время сброса и несколько аккаунтов</a></strong>.</p><p>Вы научитесь:</p><ul><li>Как интерпретировать индикатор прогресса</li><li>Как рассчитывается обратный отсчёт времени сброса</li><li>Формат вывода при наличии нескольких аккаунтов</li><li>Принципы генерации индикатора прогресса</li></ul></blockquote><hr><h2 id="приложение-ссылка-на-исходныи-код" tabindex="-1">Приложение: ссылка на исходный код <a class="header-anchor" href="#приложение-ссылка-на-исходныи-код" aria-label="Permalink to &quot;Приложение: ссылка на исходный код&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы раскрыть расположение исходного кода</strong></summary><blockquote><p>Обновлено: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th><th>Строка</th></tr></thead><tbody><tr><td>Определение инструмента mystatus</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/mystatus.ts" target="_blank" rel="noreferrer"><code>plugin/mystatus.ts</code></a></td><td>29-33</td></tr><tr><td>Описание инструмента</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/mystatus.ts" target="_blank" rel="noreferrer"><code>plugin/mystatus.ts</code></a></td><td>30-31</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Параллельный запрос всех платформ</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/mystatus.ts" target="_blank" rel="noreferrer"><code>plugin/mystatus.ts</code></a></td><td>49-56</td></tr><tr><td>Сбор и объединение результатов</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/mystatus.ts" target="_blank" rel="noreferrer"><code>plugin/mystatus.ts</code></a></td><td>58-89</td></tr></tbody></table><p><strong>Ключевые константы</strong>: Нет (в этом разделе в основном описываются способы вызова, не затрагиваются конкретные константы)</p><p><strong>Ключевые функции</strong>:</p><ul><li><code>mystatus()</code>: основная функция инструмента mystatus, читает файл аутентификации и параллельно запрашивает все платформы (<code>plugin/mystatus.ts:29-33</code>)</li><li><code>collectResult()</code>: собирает результаты запроса в массивы results и errors (<code>plugin/mystatus.ts:100-116</code>)</li></ul></details>`,66)])])}const g=t(n,[["render",o]]);export{c as __pageData,g as default};
